    code,
    client_id,
    redirect_uri,
    scope: requestedScopes.join(' '),
    sub: sess.sub,
    username: sess.username,
    iat: nowSec(),
    exp: nowSec() + AUTH_CODE_TTL_SECONDS,
    pkce: code_challenge
